-- Roady's fuel_data upsert  April 2026 gallon report
-- Schema: fuel_data(stop_id text, month text, gallons numeric, aggregators jsonb,
--                   fleets jsonb, rack jsonb, updated_at timestamptz,
--                   PRIMARY KEY (stop_id, month))
-- 'rack' is intentionally NOT updated below so any user-edited tax/freight config is preserved.

BEGIN;

-- April 2026 (authoritative from CSV report) ----------------------------
ON CONFLICT (stop_id, month) DO UPDATE SET
  gallons     = EXCLUDED.gallons,
  aggregators = EXCLUDED.aggregators,
  fleets      = EXCLUDED.fleets,
  updated_at  = now();

-- March 2026 (back-calculated from vs-prior delta). DO NOTHING preserves
-- any existing March record. Switch to DO UPDATE if you want to overwrite.
ON CONFLICT (stop_id, month) DO NOTHING;

COMMIT;

-- Verify totals match the CSV:
--   SELECT month, COUNT(*) AS stops, SUM(gallons) AS total
--     FROM public.fuel_data
--     WHERE month IN ('2026-03','2026-04')
--     GROUP BY month ORDER BY month;
-- Expected April: 191 stops, ~2,243,359 gal.
